import { createSlice } from '@reduxjs/toolkit'
import axios from 'axios'


export const cartSlice = createSlice({
    name: 'cart',
    initialState: {cartItems: []},
    reducers: {
        cartAddItem: (state, action) => {
                const item = action.payload;
                const existItem = state.cartItems.find(x => x.product === item.product)
                if (existItem){
                    // state.cartItems.map(x => 
                    //     x.product === existItem.product ? item : x
                    // )

                    // if the item already exists in the cart, increase the qty by the new qty
                    const index = state.cartItems.findIndex(x => x.id = item.id);
                    state.cartItems[index].qty += item.qty;
                } else {
                    state.cartItems.push(item);
                }
        },

        cartRemoveItem: (state, action) => { 
            // const index = state.cartItems.indexOf(action.payload)
        },
    }
})
export const { cartAddItem, cartRemoveItem } = cartSlice.actions
export default cartSlice.reducer;


export const addToCart = (id, qty) => async (dispatch, getState) => {
    const { data } = await axios.get(`/api/products/${id}`);

    dispatch(cartAddItem({
        product: data.id,
        name: data.name,
        image: data.image,
        price: data.price,
        countInStock: data.countInStock,
        qty
    }));

    localStorage.setItem('cartItems', JSON.stringify(getState().cart.cartItems));
}
